import * as unplugin from 'unplugin';

declare type TransformFunction = (moduleName: string, importName: string) => string;
interface ModuleOpts {
    module: string;
    transform?: TransformFunction;
    version?: string;
}
interface Options {
    cwd?: string;
    enforce?: 'pre' | 'post';
    endpoint?: 'npm' | 'gh';
    modules?: ModuleOpts[];
}

declare const _default: unplugin.UnpluginInstance<Options>;

export { _default as default };
